export interface AgentMetrics {
  agentName: string;
  executionTime: number;      // 执行时间（毫秒）
  tokenUsage: number;         // Token 消耗量
  status: 'success' | 'failed' | 'skipped';
  errorMessage?: string;
  timestamp: Date;
}

export interface IterationMetrics {
  iterationNumber: number;
  startTime: Date;
  endTime: Date;
  totalDuration: number;      // 总耗时（毫秒）

  // 各阶段耗时
  phases: {
    productManager: number;   // 产品经理阶段
    architect: number;        // 架构设计阶段
    development: number;      // 开发阶段
    testing: number;          // 测试阶段
    deployment: number;       // 部署阶段
  };

  // Agent 执行详情
  agents: AgentMetrics[];

  // 统计数据
  stats: {
    totalAgents: number;
    successCount: number;
    failedCount: number;
    totalTokens: number;
    successRate: number;      // 成功率（%）
  };

  // Git 提交信息
  commit?: {
    hash: string;
    message: string;
    branch: string;
  };
}
