#### 2. 实现性能收集器

```typescript
// src/auto-iteration-metrics.ts

export class MetricsCollector {
  private metrics: IterationMetrics[] = [];
  private currentIteration?: {
    number: number;
    startTime: Date;
    phaseStartTimes: Map<string, number>;
    agentMetrics: AgentMetrics[];
  };

  // 开始迭代
  startIteration(iterationNumber: number): void {
    this.currentIteration = {
      number: iterationNumber,
      startTime: new Date(),
      phaseStartTimes: new Map(),
      agentMetrics: []
    };
  }

  // 开始阶段
  startPhase(phaseName: string): void {
    if (!this.currentIteration) return;
    this.currentIteration.phaseStartTimes.set(phaseName, Date.now());
  }

  // 结束阶段
  endPhase(phaseName: string): number {
    const startTime = this.currentIteration?.phaseStartTimes.get(phaseName);
    if (!startTime) return 0;
    return Date.now() - startTime;
  }

  // 记录 Agent 执行
  recordAgent(metrics: AgentMetrics): void {
    this.currentIteration?.agentMetrics.push(metrics);
  }

  // 完成迭代
  completeIteration(commitInfo?: { hash: string; message: string; branch: string }): IterationMetrics {
    if (!this.currentIteration) throw new Error('No active iteration');

    const endTime = new Date();
    const totalDuration = endTime.getTime() - this.currentIteration.startTime.getTime();

    const iterationMetrics: IterationMetrics = {
      iterationNumber: this.currentIteration.number,
      startTime: this.currentIteration.startTime,
      endTime,
      totalDuration,
      phases: {
        productManager: 0,
        architect: 0,
        development: 0,
        testing: 0,
        deployment: 0
      },
      agents: this.currentIteration.agentMetrics,
      stats: this.calculateStats(),
      commit: commitInfo
    };

    this.metrics.push(iterationMetrics);
    this.currentIteration = undefined;

    return iterationMetrics;
  }

  // 计算统计数据
  private calculateStats() {
    const agents = this.currentIteration?.agentMetrics || [];
    const successCount = agents.filter(a => a.status === 'success').length;
    const failedCount = agents.filter(a => a.status === 'failed').length;
    const totalTokens = agents.reduce((sum, a) => sum + a.tokenUsage, 0);

    return {
      totalAgents: agents.length,
      successCount,
      failedCount,
      totalTokens,
      successRate: agents.length > 0 ? (successCount / agents.length) * 100 : 0
    };
  }

  // 获取性能报告
  getPerformanceReport(): PerformanceReport {
    return {
      totalIterations: this.metrics.length,
      averageDuration: this.getAverageDuration(),
      successRate: this.getOverallSuccessRate(),
      topAgents: this.getTopAgents(),
      recentTrends: this.getRecentTrends()
    };
  }
}
```

