###### 3.1 IterationLogger（迭代日志记录器）

```typescript
// src/dashboard/services/iteration-logger.service.ts

import pino from 'pino';

export interface IterationLog {
  iterationNumber: number;
  phase: 'start' | 'analysis' | 'development' | 'testing' | 'commit' | 'end';
  agent?: string;
  level: 'info' | 'warn' | 'error' | 'debug';
  message: string;
  data?: Record<string, unknown>;
  timestamp: Date;
  duration?: number;
}

export class IterationLogger {
  private logger: pino.Logger;
  private currentLogs: IterationLog[] = [];

  constructor(logDir: string = './logs') {
    this.logger = pino({
      level: 'info',
      transport: {
        target: 'pino-pretty',
        options: {
          colorize: true,
          translateTime: 'SYS:standard'
        }
      },
      // 同时输出到文件和控制台
      formatters: {
        level: (label) => {
          return { level: label };
        },
      }
    });
  }

  /**
   * 记录迭代开始
   */
  logStart(iterationNumber: number, requirement: string) {
    const log: IterationLog = {
      iterationNumber,
      phase: 'start',
      level: 'info',
      message: `迭代 #${iterationNumber} 开始`,
      data: { requirement },
      timestamp: new Date()
    };

    this.currentLogs.push(log);
    this.logger.info(log);
  }

  /**
   * 记录 Agent 执行
   */
  logAgentExecution(iterationNumber: number, agentName: string, 
                    task: string, duration: number) {
    const log: IterationLog = {
      iterationNumber,
      phase: 'development',
      agent: agentName,
      level: 'info',
      message: `${agentName} 执行任务: ${task}`,
      data: { task, duration },
      timestamp: new Date(),
      duration
    };

    this.currentLogs.push(log);
    this.logger.info(log);
  }

  /**
   * 记录错误
   */
  logError(iterationNumber: number, phase: string, error: Error) {
    const log: IterationLog = {
      iterationNumber,
      phase: phase as any,
      level: 'error',
      message: error.message,
      data: {
        stack: error.stack,
        name: error.name
      },
      timestamp: new Date()
    };

    this.currentLogs.push(log);
    this.logger.error(log);
  }

  /**
   * 记录 Git 提交
   */
  logCommit(iterationNumber: number, commitHash: string, 
            filesChanged: number) {
    const log: IterationLog = {
      iterationNumber,
      phase: 'commit',
      level: 'info',
      message: `代码已提交: ${commitHash}`,
      data: { commitHash, filesChanged },
      timestamp: new Date()
    };

    this.currentLogs.push(log);
    this.logger.info(log);
  }

  /**
   * 获取当前迭代的日志
   */
  getCurrentIterationLogs(iterationNumber: number) {
    return this.currentLogs.filter(
      log => log.iterationNumber === iterationNumber
    );
  }

  /**
   * 清理旧日志（保留最近1000条）
   */
  cleanup() {
    if (this.currentLogs.length > 1000) {
      this.currentLogs = this.currentLogs.slice(-1000);
    }
  }
}
```

###### 3.2 PerformanceMonitor（性能监控器）

```typescript
// src/dashboard/services/performance-monitor.service.ts

export interface PerformanceMetrics {
  iterationNumber: number;
  agentMetrics: {
    [agentName: string]: {
      executionCount: number;
      totalDuration: number;
      avgDuration: number;
      successCount: number;
      errorCount: number;
      lastExecutionTime: Date;
    };
  };
  systemMetrics: {
    memoryUsage: NodeJS.MemoryUsage;
    cpuUsage: number;
    timestamp: Date;
  }[];
  iterationDuration: number;
}

export class PerformanceMonitor {
  private metrics: PerformanceMetrics;
  private agentTimers: Map<string, number> = new Map();

  constructor() {
    this.metrics = {
      iterationNumber: 0,
      agentMetrics: {},
      systemMetrics: [],
      iterationDuration: 0
    };
  }

  /**
   * 开始新的迭代监控
   */
  startIteration(iterationNumber: number) {
    this.metrics.iterationNumber = iterationNumber;
    this.metrics.iterationDuration = 0;
    this.metrics.systemMetrics = [];

    // 每5秒收集一次系统指标
    const interval = setInterval(() => {
      this.collectSystemMetrics();
    }, 5000);

    // 存储定时器以便清理
    (this as any).systemMetricInterval = interval;
  }

  /**
   * 开始 Agent 执行计时
   */
  startAgent(agentName: string) {
    this.agentTimers.set(agentName, Date.now());

    // 初始化 Agent 指标
    if (!this.metrics.agentMetrics[agentName]) {
      this.metrics.agentMetrics[agentName] = {
        executionCount: 0,
        totalDuration: 0,
        avgDuration: 0,
        successCount: 0,
        errorCount: 0,
        lastExecutionTime: new Date()
      };
    }
  }

  /**
   * 结束 Agent 执行计时
   */
  endAgent(agentName: string, success: boolean) {
    const startTime = this.agentTimers.get(agentName);
    if (!startTime) return;

    const duration = Date.now() - startTime;
    const metrics = this.metrics.agentMetrics[agentName];

    metrics.executionCount++;
    metrics.totalDuration += duration;
    metrics.avgDuration = metrics.totalDuration / metrics.executionCount;
    metrics.lastExecutionTime = new Date();

    if (success) {
      metrics.successCount++;
    } else {
      metrics.errorCount++;
    }

    this.agentTimers.delete(agentName);
  }

  /**
   * 收集系统指标
   */
  private collectSystemMetrics() {
    const memUsage = process.memoryUsage();

    this.metrics.systemMetrics.push({
      memoryUsage: memUsage,
      cpuUsage: process.cpuUsage().user / 1000000, // 转换为秒
      timestamp: new Date()
    });
  }

  /**
   * 结束迭代监控
   */
  endIteration() {
    clearInterval((this as any).systemMetricInterval);
    this.metrics.iterationDuration = 
      Date.now() - this.metrics.systemMetrics[0]?.timestamp.getTime() || 0;
  }

  /**
   * 获取性能指标
   */
  getMetrics(): PerformanceMetrics {
    return JSON.parse(JSON.stringify(this.metrics));
  }

  /**
   * 获取 Agent 性能摘要
   */
  getAgentSummary(agentName: string) {
    return this.metrics.agentMetrics[agentName];
  }

  /**
   * 生成性能报告
   */
  generateReport(): string {
    const report = [];

    report.push('=== 性能监控报告 ===\n');
    report.push(`迭代次数: #${this.metrics.iterationNumber}\n`);
    report.push(`总耗时: ${this.metrics.iterationDuration}ms\n\n`);

    report.push('Agent 执行统计:\n');
    for (const [agent, metrics] of Object.entries(this.metrics.agentMetrics)) {
      report.push(`  ${agent}:`);
      report.push(`    执行次数: ${metrics.executionCount}`);
      report.push(`    平均耗时: ${metrics.avgDuration.toFixed(2)}ms`);
      report.push(`    成功率: ${((metrics.successCount / metrics.executionCount) * 100).toFixed(2)}%\n`);
    }

    return report.join('\n');
  }
}
