  phase TEXT NOT NULL,
  agent TEXT,
  level TEXT NOT NULL,
  message TEXT NOT NULL,
  data TEXT, -- JSON 字符串
  duration INTEGER,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);

-- 性能指标表
CREATE TABLE IF NOT EXISTS performance_metrics (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  iteration_number INTEGER NOT NULL,
  agent_name TEXT NOT NULL,
  execution_count INTEGER DEFAULT 0,
  total_duration INTEGER DEFAULT 0,
  avg_duration REAL DEFAULT 0,
  success_count INTEGER DEFAULT 0,
  error_count INTEGER DEFAULT 0,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);

-- 系统指标表
CREATE TABLE IF NOT EXISTS system_metrics (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  iteration_number INTEGER NOT NULL,
  memory_used INTEGER,
  memory_total INTEGER,
  cpu_usage REAL,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);

-- 索引优化
CREATE INDEX idx_logs_iteration ON iteration_logs(iteration_number);
CREATE INDEX idx_logs_created ON iteration_logs(created_at);
CREATE INDEX idx_perf_iteration ON performance_metrics(iteration_number);
```

##### 5. API 接口设计

```typescript
// src/dashboard/routes/monitoring.ts

/**
 * 获取迭代日志
