 */
interface GetLogsResponse {
  logs: IterationLog[];
  total: number;
}

/**
 * 获取性能指标
 * GET /api/iterations/:iterationNumber/metrics
 */
interface GetMetricsResponse {
  agentMetrics: PerformanceMetrics['agentMetrics'];
  systemMetrics: PerformanceMetrics['systemMetrics'];
  iterationDuration: number;
}

/**
 * 获取实时系统状态
 * GET /api/system/realtime
 */
interface RealtimeStatusResponse {
  currentIteration: number;
  activeAgents: string[];
  memoryUsage: NodeJS.MemoryUsage;
  logsInLastMinute: number;
}

/**
 * WebSocket 事件推送
 * ws://localhost:3000/api/ws
 */
interface WebSocketEvents {
  'log.created': IterationLog;
  'metrics.updated': PerformanceMetrics;
  'agent.started': { agentName: string; timestamp: Date };
  'agent.completed': { agentName: string; duration: number; success: boolean };
  'iteration.completed': { iterationNumber: number; duration: number };
}
